[DataEventHandler(tableStr(InventOnhandTmp), DataEventType::Inserting)]
public static void InventOnhandTmp_onInserting(Common sender, DataEventArgs e)
{
    InventOnhandTmp inventOnhandTmp = sender as InventOnhandTmp;

    //InventTable inventTable = InventTable::find(inventOnhandTmp.ItemId);
    inventOnhandTmp.ItemName = EcoResProductTranslation::findByProductLanguage(InventTable::find(inventOnhandTmp.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;

}
